const body = $input.first().json.body || $input.first().json || {};
const candidateId = parseInt(body.candidate_id);
const jobId = parseInt(body.job_opening_id);
const emailType = (body.email_type || '').trim().toLowerCase();
const recipientEmail = (body.recipient_email || '').trim();
const candidateName = (body.candidate_name || '').trim();
const jobTitle = (body.job_title || '').trim();

const validTypes = ['rejection', 'interview_invite', 'offer', 'custom'];

if (!candidateId || isNaN(candidateId)) {
  return [{ json: { error: true, message: 'Valid candidate_id required', status: 400 } }];
}
if (!jobId || isNaN(jobId)) {
  return [{ json: { error: true, message: 'Valid job_opening_id required', status: 400 } }];
}
if (!validTypes.includes(emailType)) {
  return [{ json: { error: true, message: 'email_type must be: ' + validTypes.join(', '), status: 400 } }];
}
if (!recipientEmail || !recipientEmail.includes('@')) {
  return [{ json: { error: true, message: 'Valid recipient_email required', status: 400 } }];
}
if (emailType !== 'custom' && !candidateName) {
  return [{ json: { error: true, message: 'candidate_name required for ' + emailType + ' emails', status: 400 } }];
}
if (emailType !== 'custom' && !jobTitle) {
  return [{ json: { error: true, message: 'job_title required for ' + emailType + ' emails', status: 400 } }];
}

let subject = '';
let emailBody = '';

if (emailType === 'rejection') {
  subject = 'Application Update - ' + jobTitle;
  emailBody = 'Dear ' + candidateName + ',\n\nThank you for your interest in the ' + jobTitle + ' position and for taking the time to apply.\n\nAfter careful review of all applications, we regret to inform you that we have decided to move forward with other candidates whose qualifications more closely match our current requirements.\n\nWe appreciate your interest in our organization and encourage you to apply for future openings that match your skills and experience.\n\nWe wish you all the best in your job search and future endeavors.\n\nBest regards,\nHR Department';
} else if (emailType === 'interview_invite') {
  subject = 'Interview Invitation - ' + jobTitle;
  emailBody = 'Dear ' + candidateName + ',\n\nWe are pleased to inform you that after reviewing your application for the ' + jobTitle + ' position, we would like to invite you for an interview.\n\nPlease reply to this email with your availability for the coming week, and we will schedule a convenient time.\n\nWe look forward to speaking with you.\n\nBest regards,\nHR Department';
} else if (emailType === 'offer') {
  subject = 'Job Offer - ' + jobTitle;
  emailBody = 'Dear ' + candidateName + ',\n\nWe are delighted to extend an offer for the ' + jobTitle + ' position.\n\nPlease find the details of the offer attached. We kindly ask you to review and respond within 5 business days.\n\nCongratulations, and we look forward to welcoming you to our team!\n\nBest regards,\nHR Department';
} else {
  subject = body.custom_subject || 'Regarding Your Application - ' + jobTitle;
  emailBody = body.custom_body || '';
}

// Allow overrides
if (body.custom_subject) subject = body.custom_subject;
if (body.custom_body) emailBody = body.custom_body;

return [{ json: { error: false, candidate_id: candidateId, job_opening_id: jobId, email_type: emailType, recipient_email: recipientEmail, candidate_name: candidateName, job_title: jobTitle, subject: subject, body: emailBody } }];

const query = $input.first().json.query || {};
const candidateId = parseInt(query.candidate_id);
const jobId = parseInt(query.job_id);
let sql = 'SELECT el.*, c.candidate_name FROM email_log el INNER JOIN candidates c ON c.id = el.candidate_id WHERE 1=1';
if (candidateId && !isNaN(candidateId)) sql += ' AND el.candidate_id = ' + candidateId;
if (jobId && !isNaN(jobId)) sql += ' AND el.job_opening_id = ' + jobId;
sql += ' ORDER BY el.sent_at DESC';
return [{ json: { error: false, sql: sql } }];
